def _load_config(path: str) -> Dict[str, Any]:
    with open(path, "r", encoding="utf-8") as f:
        return json.load(f)


def _validate_config(cfg: Dict[str, Any]) -> None:
    if "services" not in cfg or not isinstance(cfg["services"], list):
        raise ValueError("Config must contain 'services' as a list")
    for svc in cfg["services"]:
        if "name" not in svc:
            raise ValueError("Each service must have 'name'")
        if "routes" in svc and not isinstance(svc["routes"], list):
            raise ValueError(f"Service '{svc.get('name')}' routes must be a list if provided")
    if "upstreams" in cfg:
        if not isinstance(cfg["upstreams"], list):
            raise ValueError("'upstreams' must be a list")
        for ups in cfg["upstreams"]:
            if "name" not in ups:
                raise ValueError("Each upstream must have 'name'")
            if "targets" in ups and not isinstance(ups["targets"], list):
                raise ValueError(f"Upstream '{ups.get('name')}' targets must be a list if provided")


def apply_config(kong: KongAdmin, cfg: Dict[str, Any]) -> Dict[str, Any]:
    _validate_config(cfg)

    result: Dict[str, Any] = {"services": [], "routes": [], "upstreams": [], "targets": []}

    for svc in cfg.get("services", []):
        svc_body = dict(svc)
        routes = svc_body.pop("routes", [])
        service_resp = kong.ensure_service(svc_body)
        result["services"].append(service_resp)

        for route in routes:
            route_resp = kong.ensure_route(service_name=svc_body["name"], route=route)
            result["routes"].append(route_resp)

    for ups in cfg.get("upstreams", []):
        ups_body = dict(ups)
        targets = ups_body.pop("targets", [])
        upstream_resp = kong.ensure_upstream(ups_body)
        result["upstreams"].append(upstream_resp)

        for tgt in targets:
            target_resp = kong.ensure_target(upstream_name=ups_body["name"], target=tgt)
            result["targets"].append(target_resp)

    return result


